sp_rectangle_menu_item.record_script:
// Menu Item Label
var label = 'Awaiting Acceptance';

// maximum number of entries in this Menu
var max = 5;

var t = data;  // shortcut
t.items = [];

// current user
var u = gs.getUser().getID();

// use record watchers to tell header when to update dropdown counts
var filter = 'state=1^assigned_toDYNAMIC90d1921e5f510100a9ad2572f2b477fe';
t.record_watchers = [];
t.record_watchers.push({'table':'x_153465_discovert_route_task_instance','filter': filter});

var a = new GlideAggregate('x_153465_discovert_route_task_instance');
a.addEncodedQuery(filter);
a.addAggregate("COUNT");

a.query();
var totcount=0;
if(a.next()){


totcount = a.getAggregate("COUNT");
}
//gs.info("The awating acceptance count is: " + totcount)
//gs.info("The awating acceptance count is" + a.getAggregate("COUNT"));

var z = new GlideRecord('x_153465_discovert_route_task_instance');
z.addActiveQuery();
z.addEncodedQuery(filter);
z.orderByDesc('sys_updated_on');
z.setLimit(max);
z.query();


while (z.next()) {
   t.items.push({
    title: z.getValue('task_name') ,
    type: 'link',
    href: '?sys_id='+ z.getValue('sys_id') + '&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance'
  }); 

  if (!z.canRead())
    continue;

  var a = {};
  //$sp.getRecordValues(a, z, 'short_description,sys_id,number,sys_updated_on');
  if (z.short_description.nil())
    a.short_description = "(No description)";
  a.__table = z.getTableName();
  a.type = 'record';
  //a.sortOrder = z.sys_updated_on.getGlideObject().getNumericValue();
  //t.items.push(a);

}
t.items.sort(function(a, b) {
  return b.sortOrder - a.sortOrder;
});
//t.items = t.items.slice(0, max); // only want first 30
t.items = t.items.slice(0, 5); 
//t.count = t.items.length;
t.count = totcount;

var link = {title: gs.getMessage('View all requests'), type: 'link', href: '?id=discovertasker_detailsdrilldown&view=Unassigned&table=x_153465_discovert_route_task_instance&filter=stateIN1^assigned_to='+u + '&label='+label, items: []};
t.items.push(link); // put 'View all requests' last
